```class Solution:
    def calculate(self, s: str) -> int:
        stack = []
        num = 0
        sign = 1
        res = 0
        for i in range(len(s)):
            if s[i].isdigit():
                num = num * 10 + int(s[i])
            if (not s[i].isdigit() and not s[i].isspace()) or i == len(s) - 1:
                if s[i] == '+':
                    res += sign * num
                elif s[i] == '-':
                    res += sign * -num
                elif s[i] == '*':
                    stack.append(sign * num)
                    sign = 1
                elif s[i] == '/':
                    stack.append(sign * int(num / stack.pop()))
                    sign = 1
                num = 0
                if s[i] in ['+', '-', '*']:
                    sign = 1 if s[i] == '+' else -1 if s[i] == '-' else 1
        while stack:
            res += stack.pop()
        return res
